CREATE OR REPLACE VIEW vm_com_m_receipt (membership_no, receipt_no, receipt_date, calcint_date, memname, member_group_no, groupname, recept_amount, recept_amount_thai, money_type_id, money_type_name, manager_name, entry_id, user_name) AS SELECT sc_com_m_receipt.membership_no,
         sc_com_m_receipt.receipt_no,   
         sc_com_m_receipt.receipt_date,   
