         ( select member_group_name FROM sc_mem_m_ucf_member_group where sc_mem_m_ucf_member_group.member_group_no = sc_com_m_receipt.member_group_no ) as groupname,   
         sc_com_m_receipt.recept_amount,   
         pka_com_function.fp_get_moneythai(sc_com_m_receipt.recept_amount )  as recept_amount_thai,   
         sc_com_m_receipt.money_type_id,   
         sc_com_m_ucf_money_type.money_type_name,   
         sc_cnt_m_coop.manager_name,   
         
         sc_com_m_receipt.entry_id ,
         si_security_user.user_name 
         --TGE เงินโอน ให้ออกลายเซนต์ หัวหน้าการเงิน
         --decode( sc_com_m_receipt.money_type_id , 'CSH' , sc_com_m_receipt.entry_id , 'SUWIMOL') as entry_id ,   
